// CLX Lead Research v2 — Parse Claude Response
// Reads Claude API response via $input.item.json and the current lead
// via $('Split In Batches').first().json (stable first-item accessor).

const response = $input.item.json;
const lead = $('Split In Batches').first().json;

const rawText = (response && response.content && response.content[0] && response.content[0].text) || '';

let research;
try {
  const cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  research = JSON.parse(cleaned);
} catch (e) {
  research = {
    research_summary: rawText.substring(0, 500),
    likely_business_need: 'Manual review needed',
    research_angle: 'General outreach'
  };
}

const now = new Date().toISOString();

return {
  json: {
    id: lead.id,
    research_summary: research.research_summary || '',
    likely_business_need: research.likely_business_need || '',
    research_angle: research.research_angle || '',
    lead_status: 'Researched',
    researched_at: now,
    updated_at: now
  }
};

// CLX Lead Research v2 — Prep Update Lead
// Builds the RPC body from $input.item.json (the Parse output for this lead).

const item = $input.item.json;

const body = {
  p_lead_id: item.id,
  p_fields: {
    research_summary: item.research_summary,
    likely_business_need: item.likely_business_need,
    research_angle: item.research_angle,
    lead_status: 'Researched',
    researched_at: item.researched_at
  }
};

console.log('PREP UPDATE:', JSON.stringify({ lead_id: item.id, status: body.p_fields.lead_status }));

return { json: { ...item, rpc_body: JSON.stringify(body) } };
